                // Check if the value is affirmative for options without arguments
                boolean isAffirmative = "yes".equalsIgnoreCase(value)
                        || "true".equalsIgnoreCase(value)
                        || "1".equalsIgnoreCase(value);
                if (isAffirmative) {
                    cmd.addOption(opt);
                }
                // If not affirmative, do not add the option but continue processing others
                continue;
            }

            cmd.addOption(opt);
        }
    }
